import java.io.*;
import javax.servlet.*;
import javax.servlet.http.*;
import org.owasp.esapi.ESAPI;
import org.owasp.esapi.codecs.HTMLEntityCodec;

public class XSSFixedServlet extends HttpServlet {
    protected void doPost(HttpServletRequest request, HttpServletResponse response)
            throws ServletException, IOException {
        String userInput = request.getParameter("input");
        PrintWriter out = response.getWriter();

        // Encode user input using ESAPI's HTML entity codec
        HTMLEntityCodec codec = new HTMLEntityCodec();
        String encodedInput = codec.encodeForHTML(userInput);

        // Output encoded user input
        out.println("<html>");
        out.println("<body>");
        out.println("<h1>User Input: " + encodedInput + "</h1>");
        out.println("</body>");
        out.println("</html>");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
